  @{Id='b001_39'; Name='next_step_guidance'; Title='Next-Step Guidance'; Summary='Prints next commands and recommends next implementation step.'; Workflow='Handoff / next-step guidance'; Root='.foundation/next-steps'; Components=@('next-commands','implementation-recommendations','handoff-guidance')}
