$templatePath = Join-Path $PSScriptRoot 'templates\b001_domain_script.template.sh'
$template = [System.IO.File]::ReadAllText($templatePath)

foreach ($d in $domains) {
  $fileName = "$($d.Id)_$($d.Name).sh"
  $componentLines = ($d.Components | ForEach-Object { "  `"$_|Scaffold boundary for $_ within $($d.Title).`"" }) -join "`n"
  $content = $template
  $content = $content.Replace('@SCRIPT_ID@', $d.Id)
  $content = $content.Replace('@SCRIPT_NAME@', $d.Name.Replace('_','-'))
  $content = $content.Replace('@TITLE@', $d.Title)
  $content = $content.Replace('@SUMMARY@', $d.Summary)
  $content = $content.Replace('@WORKFLOW@', $d.Workflow)
  $content = $content.Replace('@ROOT@', $d.Root)
  $content = $content.Replace('@EVIDENCE_NAME@', $d.Name)
  $content = $content.Replace('@FILE_NAME@', $fileName)
  $content = $content.Replace('@COMPONENT_LINES@', $componentLines)
  [System.IO.File]::WriteAllText((Join-Path $base $fileName), $content, [System.Text.UTF8Encoding]::new($false))
  Write-Output "Wrote $fileName"
}
